  1	import { type FC, type MouseEvent, useCallback, useMemo } from 'react';
  2	import { type Location, useLocation, useNavigate } from 'react-router-dom-v5-compat';
  3	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
  4	
  5	import { PlanModelRef } from '@kubev2v/types';
  6	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
  7	import {
  8	  Button,
  9	  ButtonVariant,
 10	  useWizardContext,
 11	  type WizardFooterProps,
 12	  WizardFooterWrapper,
 13	} from '@patternfly/react-core';
 14	import { useForkliftTranslation } from '@utils/i18n';
 15	
 16	import { useCreatePlanFormContext } from './hooks/useCreatePlanFormContext';
 17	import { useStepValidation } from './hooks/useStepValidation';
 18	import { PlanWizardStepId } from './constants';
 19	import type { CreatePlanFormData } from './types';
 20	
 21	type CreatePlanWizardFooterProps = Partial<Pick<WizardFooterProps, 'nextButtonText' | 'onNext'>> & {
 22	  hasError?: boolean;
 23	};
 24	
 25	const CreatePlanWizardFooter: FC<CreatePlanWizardFooterProps> = ({
 26	  hasError = false,
 27	  nextButtonText,
 28	  onNext: onSubmit,
 29	}) => {
 30	  const navigate = useNavigate();
 31	  const location: Location<CreatePlanFormData> = useLocation();
 32	  const { t } = useForkliftTranslation();
 33	  const [activeNamespace] = useActiveNamespace();
 34	  const {
 35	    formState: { isSubmitting },
 36	  } = useCreatePlanFormContext();
 37	  const { validateStep } = useStepValidation();
 38	  const { activeStep, goToNextStep, goToPrevStep, goToStepById } = useWizardContext();
 39	
 40	  const canSkipToReview = useMemo(
 41	    () =>
 42	      activeStep.id === PlanWizardStepId.MigrationType ||
 43	      activeStep.id === PlanWizardStepId.OtherSettings,
 44	    [activeStep.id],
 45	  );
 46	
 47	  const isBackDisabled = hasError || activeStep.id === PlanWizardStepId.General || isSubmitting;
 48	  const isNextDisabled = hasError || isSubmitting;
 49	
 50	  const onNextClick = useCallback(
 51	    async (event: MouseEvent<HTMLButtonElement>) => {
 52	      if (onSubmit) return onSubmit(event);
 53	
 54	      const isValid = await validateStep(activeStep.id as PlanWizardStepId);
 55	      if (isValid) {
 56	        await goToNextStep();
 57	      }
 58	
 59	      return undefined;
 60	    },
 61	    [onSubmit, validateStep, activeStep.id, goToNextStep],
 62	  );
 63	
 64	  const onSkipToReviewClick = useCallback(async () => {
 65	    const isValid = await validateStep(activeStep.id as PlanWizardStepId);
 66	    if (isValid) {
 67	      goToStepById(PlanWizardStepId.ReviewAndCreate);
 68	    }
 69	  }, [validateStep, activeStep.id, goToStepById]);
 70	
 71	  const onCancel = useCallback(() => {
 72	    if (location.state?.sourceProvider) {
 73	      navigate(-1);
 74	      return;
 75	    }
 76	
 77	    const plansListUrl = getResourceUrl({
 78	      namespace: activeNamespace,
 79	      reference: PlanModelRef,
 80	    });
 81	
 82	    navigate(plansListUrl);
 83	  }, [location.state?.sourceProvider, navigate, activeNamespace]);
 84	
 85	  return (
 86	    <WizardFooterWrapper>
 87	      <Button
 88	        data-testid="wizard-back-button"
 89	        variant={ButtonVariant.secondary}
 90	        onClick={goToPrevStep}
 91	        isDisabled={isBackDisabled}
 92	      >
 93	        {t('Back')}
 94	      </Button>
 95	      <Button
 96	        data-testid="wizard-next-button"
 97	        variant={ButtonVariant.primary}
 98	        onClick={onNextClick}
 99	        isDisabled={isNextDisabled}
100	        isLoading={isSubmitting}
101	      >
102	        {nextButtonText ?? t('Next')}
103	      </Button>
104	      {canSkipToReview && (
105	        <Button
106	          data-testid="wizard-review-button"
107	          variant={ButtonVariant.tertiary}
108	          onClick={onSkipToReviewClick}
109	        >
110	          {t('Skip to review')}
111	        </Button>
112	      )}
113	      <Button
114	        data-testid="wizard-cancel-button"
115	        variant={ButtonVariant.secondary}
116	        onClick={onCancel}
117	      >
118	        {t('Cancel')}
119	      </Button>
120	    </WizardFooterWrapper>
121	  );
122	};
123	
124	export default CreatePlanWizardFooter;

